    comps=[]
    for i in range(S):
        for j in range(S):
            if g[i][j] and not seen[i][j]:
                stack=[(i,j)];cells=[];seen[i][j]=1
                while stack:
                    r,c=stack.pop();cells.append((r,c))
                    for dr in(-1,0,1):
                        for dc in(-1,0,1):
                            a,b=r+dr,c+dc
                            if 0<=a<S and 0<=b<S and g[a][b] and not seen[a][b]:
                                seen[a][b]=1;stack.append((a,b))
